+        let keys = vec![&key1[..], &key2[..]];
+        let values = vec![&value1[..], &value2[..]];
+
+        let result = mha.forward(&query, &keys, &values);
+
+        assert_eq!(result.len(), 64);
+        assert!(result.iter().all(|x| x.is_finite()));
+    }
+}
