+
+    #[test]
+    fn test_distance_consistency_with_poincare() {
+        let lorentz_model = LorentzModel::new(-1.0);
+        let poincare_ball = PoincareBall::new(-1.0);
+
+        let p1 = vec![0.2, 0.3];
