+    result_ids: Vec<i64>,
+    latency_us: i64,
+    ef_search: i32,
+    probes: i32,
+) -> Result<String, Box<dyn std::error::Error + Send + Sync>> {
+    let tracker = LEARNING_MANAGER.get_tracker(table_name)
+        .ok_or_else(|| format!("Learning not enabled for table: {}", table_name))?;
