+    let trajectory = QueryTrajectory::new(
+        query_vector,
+        result_ids.iter().map(|&id| id as u64).collect(),
+        latency_us as u64,
+        ef_search as usize,
+        probes as usize,
+    );
+
+    tracker.record(trajectory);
+
+    Ok(format!("Trajectory recorded for {} results", result_ids.len()))
+}
+
+/// Clear all learning data for a table
+///
+/// # Examples
+///
+/// ```sql
